changeSet.sql:
ALTER TABLE patient_encounters
DROP CONSTRAINT IF EXISTS ck_patient_encounters_cancel_only_when_new;

ALTER TABLE patient_encounters
  ADD CONSTRAINT ck_patient_encounters_cancel_only_when_allowed_status
    CHECK (
      status <> 'CANCELLED'
        OR status IN ('NEW', 'WAITING_TRIAGE', 'PENDING_PAYMENT')
      );


CREATE UNIQUE INDEX IF NOT EXISTS uq_patient_one_ongoing_encounter
  ON patient_encounters (patient_id)
  WHERE status = 'ONGOING';


CREATE OR REPLACE FUNCTION set_department_daily_sequence_number_for_patient_encounter()
          RETURNS trigger AS $$
          DECLARE
next_sequence_number integer;
BEGIN

              IF NEW.encounter_date IS NULL THEN
                  NEW.encounter_date := CURRENT_DATE;
END IF;

INSERT INTO department_daily_encounter_sequence_counter
  (department_id, encounter_date, last_used_sequence_number)
VALUES
  (NEW.department_id, NEW.encounter_date, 1)
  ON CONFLICT (department_id, encounter_date)
              DO UPDATE
                           SET last_used_sequence_number =
                           department_daily_encounter_sequence_counter.last_used_sequence_number + 1
                           RETURNING last_used_sequence_number
                 INTO next_sequence_number;

NEW.department_daily_sequence_number := next_sequence_number;

RETURN NEW;
END;
          $$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trigger_set_department_daily_sequence_number
              ON patient_encounters;

CREATE TRIGGER trigger_set_department_daily_sequence_number
  BEFORE INSERT ON patient_encounters
  FOR EACH ROW
  EXECUTE FUNCTION set_department_daily_sequence_number_for_patient_encounter();


CREATE OR REPLACE FUNCTION validate_emergency_encounter_creation()
          RETURNS trigger AS $$
BEGIN
              IF NEW.encounter_type = 'EMERGENCY'
                 AND EXISTS (
                     SELECT 1
                     FROM patient_encounters pe
                     WHERE pe.patient_id = NEW.patient_id
                       AND pe.status = 'ONGOING'
                       AND (TG_OP = 'INSERT' OR pe.id <> NEW.id)
                 )
              THEN
                  RAISE EXCEPTION 'Patient already has an ongoing encounter. Cannot create a new emergency encounter.';
END IF;

RETURN NEW;
END;
          $$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_validate_emergency_encounter_creation
              ON patient_encounters;

CREATE TRIGGER trg_validate_emergency_encounter_creation
  BEFORE INSERT OR UPDATE ON patient_encounters
                     FOR EACH ROW
                     EXECUTE FUNCTION validate_emergency_encounter_creation();
